// Solution
function findRange(arr) {
    if (arr.length === 0) return [];
    arr.sort((a, b) => a - b);
    let currentRange = [arr[0], arr[0]];
    for (let i = 1; i < arr.length; i++) {
        if (arr[i] === currentRange[1] + 1) {
            currentRange[1] = arr[i];
        } else {
            if (currentRange[1] - currentRange[0] > arr[i] - arr[i - 1]) {
                return currentRange;
            }
            currentRange = [arr[i], arr[i]];
        }
    }
    return currentRange;
}
